// `SingleDelivery::send_single_message(pre, post, m, dst, sm, params)` is a
    // fully deterministic `open spec(checked)`:
    //
    //   let old_ack_state = ack_state_lookup(dst, pre.send_state);
    //   let new_seqno     = old_ack_state.num_packets_acked
    //                     + old_ack_state.un_acked.len() + 1;
    //   if new_seqno > params.max_seqno {
    //       &&& post == pre
    //       &&& sm is None
    //   } else {
    //       &&& sm == Some(SingleMessage::<MT>::Message{ seqno: new_seqno, m, dst })
    //       &&& post == SingleDelivery{ send_state: pre.send_state.insert(dst, ...), ..pre }
    //   }
    //
    // We can derive abstract-view equality for both r and post.  But the
    // postcondition `det_send_single_cmessage_equal` demands *concrete*
    // `HashMap<V>` equality on `post*.send_state.epmap` and
    // `post*.receive_state.epmap`, and `HashMap<V>::view` is declared
    // `uninterp`, so Verus has no axiom tying two concrete `HashMap<V>`s
    // (returned by the external `send_single_cmessage`) to each other even
    // when their views coincide.  The proof here closes everything that
    // *is* provable -- abstract Map equality on the underlying `epmap@`.

    let pre_v   = pre_self_@;
    let post1_v = post1_self_@;
    let post2_v = post2_self_@;
    let params  = AbstractParameters::static_params();

    assert(
        r1 is Some && r2 is None
        && SingleDelivery::send_single_message(pre_v, post1_v, m@, dst@, Some(r1->Some_0@), params)
        && SingleDelivery::send_single_message(pre_v, post2_v, m@, dst@, None, params)
        ==> false
    );
    assert(
        r1 is None && r2 is Some
        && SingleDelivery::send_single_message(pre_v, post1_v, m@, dst@, None, params)
        && SingleDelivery::send_single_message(pre_v, post2_v, m@, dst@, Some(r2->Some_0@), params)
        ==> false
    );

    assert(
        r1 is Some && r2 is Some
        && SingleDelivery::send_single_message(pre_v, post1_v, m@, dst@, Some(r1->Some_0@), params)
        && SingleDelivery::send_single_message(pre_v, post2_v, m@, dst@, Some(r2->Some_0@), params)
        ==> r1->Some_0@ == r2->Some_0@ && post1_v == post2_v
    );

    assert(
        SingleDelivery::send_single_message(pre_v, post1_v, m@, dst@, None, params)
        && SingleDelivery::send_single_message(pre_v, post2_v, m@, dst@, None, params)
        ==> post1_v == post2_v
    );

    assert(
        post1_v == post2_v
        ==> post1_self_.receive_state@ == post2_self_.receive_state@
            && post1_self_.send_state@  == post2_self_.send_state@
    );

    assert(
        post1_self_.receive_state@ == post2_self_.receive_state@
        ==> post1_self_.receive_state.epmap@.map_values(|v: u64| v as nat)
            =~= post2_self_.receive_state.epmap@.map_values(|v: u64| v as nat)
    );
    assert(
        post1_self_.send_state@ == post2_self_.send_state@
        ==> post1_self_.send_state.epmap@.map_values(|v: CAckState| v@)
            =~= post2_self_.send_state.epmap@.map_values(|v: CAckState| v@)
    );
